INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Centralized pixel installation$q$, $q$Add tracking pixel IDs for ad platforms in one place instead of editing site code for each vendor tag.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Multi-platform tag support$q$, $q$Common tools in this category support pixels from Meta, Google Ads, TikTok, and similar advertising networks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Event-based firing$q$, $q$Pixels typically fire on specific site events such as page views, add-to-cart actions, and completed purchases.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$No-code setup$q$, $q$Marketers can typically configure pixels through a dashboard without developer involvement.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Reduces the need for manual code edits when adding ad-platform tracking pixels.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Centralizes pixel management, which is useful for agencies handling several client sites.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Lowers the technical barrier to conversion tracking for non-developer marketers.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Public documentation, pricing, and company details for this specific listing are limited, making it hard to evaluate before contacting the vendor.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Feature depth (e.g., server-side/conversions API support, consent management) is unverified and should be confirmed directly.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Smaller, niche pixel tools can lag behind major tag-management platforms in update cadence and platform coverage.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$What does Clicks Pixels Manager do?$q$, $q$It falls into the category of pixel/tag management tools, which let website owners install and manage advertising tracking pixels (such as Meta or Google Ads pixels) without editing site code directly.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Which ad platforms does it support?$q$, $q$Tools in this category commonly support major ad networks like Meta, Google Ads, and TikTok, but exact platform support for this specific listing should be confirmed with the vendor.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Is there a free plan?$q$, $q$Pricing has not been independently verified for this listing; contact the vendor for current plan and pricing details.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Do I need a developer to set it up?$q$, $q$Pixel manager tools are generally designed for no-code setup by marketers, though initial site integration may still involve a developer depending on the platform.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$E-commerce conversion tracking$q$, $q$Store owners use pixel managers to track add-to-cart and purchase events for ad platform optimization.$q$, $q$E-commerce store operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$Agency pixel management across client sites$q$, $q$Agencies use centralized pixel tools to manage tracking for multiple client websites from one place.$q$, $q$Digital marketing agencies$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clicks Pixels Manager is listed as a tool in the marketing pixel/tag management category вЂ” software that helps website owners install and manage tracking pixels from advertising platforms without writing custom code.$q$, $q$Tools of this type typically center on a dashboard where a user enters pixel or tag IDs for platforms like Meta Ads, Google Ads, TikTok Ads, and Google Analytics, and the tool handles firing the correct events on page views, form submissions, and purchases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Typical capabilities in this product category include centralized pixel installation across multiple ad platforms, event-based firing rules (e.g., purchase, add-to-cart, lead submission), a no-code setup flow that avoids direct source-code edits, and a dashboard for reviewing which pixels are active on a site.$q$, $q$Specific feature availability for this particular listing has not been independently verified against a public product page; prospective users should confirm exact capabilities directly with the vendor before purchasing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$No publicly documented pricing page for a product under this exact name was found. Tools in this category commonly range from free, single-site plugins to paid plans priced per site or per tracked event for agencies managing pixels across multiple client properties.$q$, $q$Anyone evaluating this tool should request current pricing directly from the vendor rather than relying on category averages.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0ea683af-dcc3-4e12-a967-2e64f028da3b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Multiple task views$q$, $q$Switch between List, Board, Gantt, Calendar, Timeline, Table, and Mind Map views of the same underlying tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Docs and Whiteboards$q$, $q$Built-in collaborative documents and visual whiteboards for planning without leaving the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Native time tracking$q$, $q$Track time directly on tasks without a separate time-tracking app, available from the Unlimited plan up.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Goals and Dashboards$q$, $q$Set measurable goals and build custom dashboards to report progress across teams and projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$ClickUp Brain (AI)$q$, $q$An AI add-on for writing assistance, task summaries, and workspace-wide question answering.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Automations$q$, $q$Rule-based automations to move tasks, assign owners, and update statuses, with usage limits scaling by plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Custom fields and statuses$q$, $q$Tailor task metadata and workflow stages to match team-specific processes.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Extremely broad feature set that can replace several separate point tools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Generous free plan with unlimited tasks and members.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Highly configurable views and permissions suited to many team types.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Frequent product updates and an active AI feature roadmap.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$The breadth of features creates a steeper learning curve than simpler single-purpose tools.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$AI features (ClickUp Brain) are priced as add-ons rather than bundled into base plans.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Free plan storage is limited (60MB), pushing active teams toward paid tiers quickly.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Some advanced reporting and security controls are reserved for Business and Enterprise tiers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Does ClickUp have a free plan?$q$, $q$Yes, ClickUp offers a Free Forever plan with unlimited tasks and members, though storage is capped at 60MB and automation runs are limited.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$How much does ClickUp cost?$q$, $q$Paid plans start at $7/user/month (Unlimited, billed annually), with Business at $12/user/month and custom Enterprise pricing. AI features are a separate add-on starting around $9/user/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Is ClickUp good for large enterprises?$q$, $q$Yes, the Enterprise plan adds SAML SSO, enterprise API access, white-labeling, HIPAA/MSA compliance options, and a dedicated customer success manager for larger organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Does ClickUp have mobile and desktop apps?$q$, $q$Yes, ClickUp has native apps for Mac and Windows as well as iOS and Android mobile apps, in addition to its web app.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Who founded ClickUp?$q$, $q$ClickUp was founded in 2017 by Zeb Evans, who serves as CEO, and Alex Yurkowski, who serves as CTO.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Cross-functional project management$q$, $q$Teams use ClickUp to plan, assign, and track work across marketing, product, and operations in one workspace.$q$, $q$Mid-size to enterprise teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Agency and client work tracking$q$, $q$Agencies use ClickUp's Spaces and custom permissions to manage multiple client projects with separate visibility.$q$, $q$Digital and creative agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Solo and small-team task management$q$, $q$Freelancers and small startups use the free plan for personal and team to-do tracking without upfront cost.$q$, $q$Freelancers and small startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Free Forever$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited tasks","Unlimited members","60MB storage","Basic views (List, Board, Calendar)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Unlimited$q$, $q$$7/user/month$q$, $q$annual (higher on monthly billing)$q$, NULL, $q$["Unlimited storage","Gantt charts","Native time tracking","Goals & portfolios","Integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Business$q$, $q$$12/user/month$q$, $q$annual (higher on monthly billing)$q$, NULL, $q$["Unlimited dashboards","Timeline views","Webhooks","Mind maps","Higher automation limits","Google SSO"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["SAML SSO","Enterprise API","White labeling","HIPAA/MSA compliance options","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClickUp is a cloud-based productivity and project management platform founded in 2017 by Zeb Evans and Alex Yurkowski, now headquartered in San Diego, California. It markets itself as a single app to replace disparate tools for task management, documentation, chat, and time tracking.$q$, $q$The platform serves teams ranging from solo freelancers to large enterprises, offering configurable workspaces (Spaces, Folders, Lists) and more than a dozen ways to view the same tasks, from Kanban boards to Gantt charts and mind maps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include task management with custom statuses and fields, multiple task views (List, Board, Gantt, Calendar, Timeline, Table, Mind Map), Docs for collaborative documentation, Whiteboards for visual planning, native time tracking, Goals for OKR-style tracking, and Dashboards for reporting.$q$, $q$ClickUp Brain adds AI-powered writing assistance, task summarization, an in-app knowledge assistant, and automation suggestions across the workspace as a paid add-on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClickUp's Free Forever plan supports unlimited tasks and members with 60MB of storage and limited automations. Paid plans are Unlimited ($7/user/month annual), Business ($12/user/month annual), and Enterprise (custom pricing).$q$, $q$ClickUp Brain AI is a separate add-on, starting around $9/user/month (annual billing) for core AI features, with an expanded 'Everything AI' tier around $28/user/month for heavier AI usage including notetaking and image generation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dbd701b9-01ba-4402-984c-660c90af0d4b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
