INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$SuccessScore health scoring$q$, $q$A composite customer health score combining usage, sentiment/NPS, support activity, billing, and engagement signals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Renewal & expansion forecasting$q$, $q$Forecasting tools to flag at-risk renewals and surface upsell/expansion opportunities.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$360-degree customer view$q$, $q$Unified account view pulling data from CRM, support desk, and product analytics integrations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Lifecycle playbooks$q$, $q$Templated task sequences and communications for onboarding, QBRs, and save motions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$SmartCS AI co-pilot$q$, $q$AI-driven insight surfacing and workflow automation for customer success managers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Executive reporting$q$, $q$Dashboards and reporting built for CS leadership and executive stakeholders.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Purpose-built specifically for B2B SaaS customer success teams rather than a general CRM.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Configurable health scoring that blends multiple data sources into one metric.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Positioned as more affordable than large enterprise CS platforms like Gainsight.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Strong focus on renewal/expansion forecasting for revenue retention.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Pricing is not published and requires a sales conversation to obtain a quote.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Primarily aimed at established SaaS companies, so very early-stage startups may find it more than they need.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Feature depth for the largest enterprise CS organizations may lag more mature platforms like Gainsight.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$What is ClientSuccess used for?$q$, $q$ClientSuccess is a customer success management platform used by B2B SaaS companies to track customer health, forecast renewals, manage onboarding, and reduce churn.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$How much does ClientSuccess cost?$q$, $q$ClientSuccess does not publish public pricing. It sells Startup, Growth, and Enterprise packages priced by license and account count through a sales quote process.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Who founded ClientSuccess?$q$, $q$ClientSuccess was founded in 2014 by Dave Blake, a former VP of Global Customer Success at Adobe.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Does ClientSuccess integrate with CRMs like Salesforce?$q$, $q$Yes, ClientSuccess is designed to integrate with CRM, support desk, and product analytics tools to build a unified customer view.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Is ClientSuccess suitable for early-stage startups?$q$, $q$ClientSuccess is generally positioned for SaaS companies in the roughly $5M to $500M ARR range, so very early-stage startups without a dedicated CS function may find simpler tools more suitable.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Churn reduction and renewal management$q$, $q$CS teams use health scores and renewal forecasting to identify at-risk accounts before contracts come up for renewal.$q$, $q$B2B SaaS customer success teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Structured onboarding$q$, $q$Teams use lifecycle playbooks to standardize onboarding steps and communications for new customers.$q$, $q$Customer success managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$Executive revenue retention reporting$q$, $q$CS leadership uses dashboards to report account health and retention trends to executives.$q$, $q$VPs of Customer Success / Chief Customer Officers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClientSuccess is a customer success management platform founded in 2014 by Dave Blake and headquartered in Lehi, Utah. It is purpose-built for B2B SaaS companies that need to track customer health, forecast renewals, and manage onboarding and expansion motions.$q$, $q$The platform is designed around the daily workflow of customer success managers (CSMs) rather than being adapted from a general CRM, and it is typically positioned as a lighter-weight, more affordable alternative to larger enterprise CS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ClientSuccess centers on a configurable customer health score (SuccessScore) that combines usage, sentiment, support, billing, and engagement signals, plus renewal and expansion forecasting to flag at-risk accounts ahead of contract dates.$q$, $q$Other core capabilities include a unified 360-degree customer view via CRM/support/product-analytics integrations, templated lifecycle playbooks for onboarding and QBRs, and an AI co-pilot (SmartCS) for surfacing insights and drafting updates.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClientSuccess does not publish self-serve pricing. It sells three packages вЂ” Startup, Growth, and Enterprise вЂ” priced by license count and number of managed customer accounts, sold as an annual subscription following a sales quote.$q$, $q$The company positions its pricing as generally lower than large enterprise CS suites like Gainsight, targeting SaaS companies roughly between $5M and $500M in annual recurring revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b85ba652-1c1b-4a44-ba69-19c2f681f148', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Appointment scheduling$q$, $q$Calendar-based scheduling with an online booking widget patients can use to self-book appointments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Clinical & treatment notes$q$, $q$Configurable note templates suited to allied health documentation needs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Telehealth$q$, $q$Built-in video consultation capability for remote appointments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Invoicing & payments$q$, $q$Integrated billing and payment processing tied to appointments and patient accounts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Automated reminders$q$, $q$SMS and email appointment reminders to reduce no-shows, billed as prepaid SMS credits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Unlimited storage and users$q$, $q$Every plan includes unlimited admin users, patient records, and file storage regardless of price tier.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Simple, transparent pricing based only on practitioner count вЂ” no feature-gated tiers to compare.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Full feature set available even on the lowest-priced solo plan.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Purpose-built for allied health workflows rather than adapted from general medical software.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$30-day free trial with no credit card required.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Focused specifically on allied health, so it may not fit general medical, dental, or hospital-scale practices.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$SMS reminders are a metered add-on cost rather than included in the base subscription.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$No free-forever plan; a paid subscription is required after the trial ends.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$How much does Cliniko cost?$q$, $q$Cliniko prices by practitioner count: $45/month for a solo practitioner, scaling up to $395/month for clinics with 26-200 practitioners. All tiers include the same full feature set.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Does Cliniko offer a free trial?$q$, $q$Yes, Cliniko offers a 30-day free trial that does not require a credit card to start.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Who is Cliniko designed for?$q$, $q$Cliniko is designed for allied health practitioners such as physiotherapists, chiropractors, psychologists, and podiatrists rather than general medical or dental practices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Does Cliniko support telehealth?$q$, $q$Yes, Cliniko includes built-in telehealth video consultation functionality.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Who founded Cliniko?$q$, $q$Cliniko was founded by Joel Friedlaender and Liora Dafner-Beach in Melbourne, Australia, and remains wholly owned by its original founders.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Solo allied health practice management$q$, $q$Independent practitioners use Cliniko to manage scheduling, notes, and billing in one system at the entry-level price tier.$q$, $q$Solo allied health practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Multi-practitioner clinic operations$q$, $q$Growing clinics use Cliniko's practitioner-based pricing to add staff without losing access to any features.$q$, $q$Multi-practitioner allied health clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$Remote/telehealth consultations$q$, $q$Practices use Cliniko's built-in telehealth to see patients remotely alongside in-person appointments.$q$, $q$Allied health clinics offering telehealth$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$1 practitioner$q$, $q$$45/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$2-5 practitioners$q$, $q$$95/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$6-8 practitioners$q$, $q$$145/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$9-12 practitioners$q$, $q$$195/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$13-25 practitioners$q$, $q$$295/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$26-200 practitioners$q$, $q$$395/month$q$, $q$monthly (1 free month if paid annually)$q$, NULL, $q$["Full feature set","Unlimited admin users","Unlimited patient records","Unlimited storage"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cliniko is cloud-based practice management software built for allied health clinics вЂ” physiotherapy, chiropractic, psychology, podiatry, and similar practices. It was founded in 2011 by Joel Friedlaender and Liora Dafner-Beach and remains headquartered in Melbourne, Australia as a privately, founder-owned company.$q$, $q$Unlike many SaaS products that gate features behind pricing tiers, Cliniko offers the same full feature set to every subscriber and scales price purely by the number of practitioners on the account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes appointment scheduling with an online patient booking widget, configurable clinical note and treatment note templates, patient record management, telehealth video consultations, invoicing, and automated SMS/email appointment reminders.$q$, $q$All subscription levels include unlimited admin/reception users, unlimited locations, unlimited patient records, and unlimited file storage вЂ” features are not split across tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cliniko prices by practitioner count rather than feature tier: $45/month for 1 practitioner, $95/month for 2-5, $145/month for 6-8, $195/month for 9-12, $295/month for 13-25, and $395/month for 26-200 practitioners.$q$, $q$A 30-day free trial requiring no credit card is available, and annual billing includes one bonus free month compared to monthly billing. SMS reminders are billed separately at roughly 10 cents per message via prepaid credits.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d221b5a0-51a9-4fa0-9bbd-a8dd91499f83', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Matter & client management$q$, $q$Centralized records for clients, matters, and related documents and communications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Time & billing$q$, $q$Time and expense tracking tied directly to invoicing and billing workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Trust accounting$q$, $q$Jurisdiction-aware IOLTA/trust accounting built into the billing module for compliant client-fund handling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Document management & e-signatures$q$, $q$Document templates, storage, and e-signature collection, with unlimited e-signatures on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Client intake (Clio Grow)$q$, $q$A companion product for lead management and automated client intake, bundled into the Complete tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$AI drafting$q$, $q$AI-assisted drafting and summarization features available on the Complete plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Calendaring & court-date tracking$q$, $q$Legal-specific calendaring that helps firms track filing and court deadlines.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Purpose-built trust accounting compliance features not found in general practice management tools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Wide adoption (400,000+ legal professionals) and a large integration ecosystem.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Tiered pricing lets solo attorneys and larger firms both find an appropriate plan.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Companion products (Clio Grow) extend the platform into client intake without switching tools.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Pricing rises significantly between tiers, with AI drafting and full intake automation reserved for the top Complete tier.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Monthly (non-annual) billing carries a notable price premium over annual billing.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Additional costs such as payment processing fees and third-party integrations add to total cost of ownership.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Feature scope may be more than very small or informal legal practices need.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$How much does Clio cost?$q$, $q$Clio Manage starts at $49/user/month for EasyStart (annual billing), with Essentials at $89, Advanced at $119, and Complete at $149/user/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Who founded Clio?$q$, $q$Clio was founded in 2007 by Jack Newton and Rian Gauvreau and is operated by Themis Solutions Inc., headquartered in Burnaby, British Columbia, Canada.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Does Clio handle trust accounting?$q$, $q$Yes, Clio includes jurisdiction-aware trust (IOLTA) accounting built into its billing module, which is a key feature for law firms handling client funds.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$What is Clio Grow?$q$, $q$Clio Grow is Clio's companion product for client intake and lead management, bundled into the Complete plan and available as an add-on to other plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Does Clio have AI features?$q$, $q$Yes, Clio's Complete plan includes AI-assisted drafting and document summarization capabilities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Is Clio available on mobile?$q$, $q$Yes, Clio has iOS and Android mobile apps in addition to its web application.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Solo attorney practice management$q$, $q$Solo practitioners use Clio's EasyStart plan for basic time tracking, billing, and trust accounting.$q$, $q$Solo attorneys$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Growing multi-attorney firms$q$, $q$Established small-to-mid-size firms use Advanced or Complete for e-signatures, advanced reporting, and AI drafting.$q$, $q$Small-to-mid-size law firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Client intake automation$q$, $q$Firms use Clio Grow to capture and automate lead intake before matters are opened in Clio Manage.$q$, $q$Law firms managing high inbound lead volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$EasyStart$q$, $q$$49/user/month$q$, $q$annual$q$, NULL, $q$["Basic time tracking","Billing","Trust accounting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Essentials$q$, $q$$89/user/month$q$, $q$annual$q$, NULL, $q$["Full practice management workflows","Client & matter management","Document management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Advanced$q$, $q$$119/user/month$q$, $q$annual$q$, NULL, $q$["Unlimited e-signatures","Advanced reporting","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$Complete$q$, $q$$149/user/month$q$, $q$annual$q$, NULL, $q$["Client intake automation (Clio Grow)","AI drafting","Full practice management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clio, built by Themis Solutions Inc., is cloud-based legal practice management software founded in 2007 by Jack Newton and Rian Gauvreau and headquartered in Burnaby, British Columbia, Canada. The company reports serving more than 400,000 legal professionals in over 130 countries.$q$, $q$Clio Manage, the flagship product, centralizes client and matter management, time tracking, billing, trust accounting, and document management for law firms, while companion product Clio Grow covers client intake and lead management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include matter and client management, calendaring with court-date tracking, time and expense tracking, document management with templates and e-signatures, and billing/invoicing with jurisdiction-aware trust (IOLTA) accounting.$q$, $q$Higher tiers add unlimited e-signatures, advanced reporting, client intake automation via Clio Grow, and AI-assisted document drafting capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clio Manage is priced in four annually billed tiers: EasyStart at $49/user/month, Essentials at $89/user/month (most popular), Advanced at $119/user/month, and Complete at $149/user/month. Monthly billing costs roughly $10-20 more per user than the annual rate.$q$, $q$Additional costs can include Clio Payments processing fees (about 2.95% + $0.20 per transaction) and third-party integrations such as QuickBooks Online.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a9597db-c7eb-4543-a969-70c7a5b25c4e', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Video upload & transcoding$q$, $q$Handles video uploads and transcodes them via FFmpeg for web playback.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Playlists & collections$q$, $q$Users can organize uploaded videos into playlists and collections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Social features$q$, $q$Includes user groups, friend requests, and private messaging alongside video hosting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Self-hosted deployment$q$, $q$Runs on a standard LAMP-style stack (PHP, MySQL/MariaDB, FFmpeg) under the operator's full control.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Open-source codebase$q$, $q$Source is freely available to modify, extend, or audit, with community forks such as ClipBucket V5.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Completely free and open-source with no licensing cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Full control over hosting, data, moderation, and monetization.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Includes social features (groups, messaging, playlists) beyond basic video hosting.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Community forks (ClipBucket V5) continue active development after the original project was archived.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Requires technical setup: PHP, MySQL/MariaDB, FFmpeg, and shell/exec access, which rules out most shared hosting.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$The original arslancb repository is archived, so evaluating which fork is actively maintained takes extra diligence.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$No vendor support or SLA вЂ” operators are responsible for their own security, backups, and scaling.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Is ClipBucket free?$q$, $q$Yes, ClipBucket is free and open-source. The only costs are for self-managed server hosting, storage, and bandwidth.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$What server requirements does ClipBucket have?$q$, $q$It requires PHP 8.0+ with specific extensions, MySQL 5.6+ or MariaDB 10.3+, FFmpeg 3+ for transcoding, and mediainfo, plus a working sendmail configuration.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Is the original ClipBucket project still maintained?$q$, $q$The original arslancb/clipbucket repository was archived in December 2022, but community forks such as ClipBucket V5 continue to ship stability and security releases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Can ClipBucket run on shared hosting?$q$, $q$It's generally not well suited to typical shared hosting because it needs shell/exec access and FFmpeg for video transcoding, which most shared hosts restrict.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Self-hosted community video site$q$, $q$Niche communities and hobbyist operators use ClipBucket to run their own branded video-sharing site outside major platforms.$q$, $q$Hobbyists and niche community builders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$Custom video platform for developers$q$, $q$Developers use ClipBucket's open-source codebase as a starting point to build a customized video platform.$q$, $q$Developers and small media companies$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClipBucket is a free, open-source PHP script for self-hosting a video-sharing website, often described as a YouTube-clone script. It lets operators run their own branded video (and optionally photo) sharing platform on their own server.$q$, $q$The original project (arslancb/clipbucket) was archived in December 2022 after slowing following its 4.1 release, but the codebase continues under community forks, most notably ClipBucket V5, which ships ongoing stability and security releases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ClipBucket includes core video hosting (upload, transcode via FFmpeg, playback) alongside social features such as playlists, collections, user groups, friend requests, and private messaging, enabling both video-sharing and lightweight social-network functionality.$q$, $q$Because it is self-hosted, operators have full control of data, moderation, and monetization, but must also manage their own server infrastructure, security patching, and scaling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClipBucket itself is free and open-source with no licensing fee. The only costs are for self-managed server hosting, storage, and bandwidth, which scale with the size of the video library and audience.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('20d0dcea-e515-425a-9158-96cea2e7f443', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Background removal$q$, $q$Automatically removes photo backgrounds with clean edges, including bulk processing of multiple images at once.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Relight$q$, $q$Lets users add, move, and adjust virtual light sources on a portrait or product photo after it was taken.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Cleanup$q$, $q$Removes unwanted objects, text, or blemishes from a photo.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Uncrop$q$, $q$Generatively expands an image's canvas or aspect ratio beyond its original borders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Image Upscaler$q$, $q$Increases image resolution using AI upscaling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Stable Diffusion XL generation$q$, $q$Direct access to text-to-image generation via Stability AI's SDXL model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Developer API$q$, $q$Metered API access to background removal, upscaling, and image generation for embedding in other applications.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Broad, focused toolkit for common image-editing tasks without needing a full design suite.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Relight is a distinctive feature not commonly offered by competing background-removal tools.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Accessible via web, mobile apps, and a Photoshop plugin, plus a developer API.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Free tier available for casual or low-volume use.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Ownership has changed twice since 2023 (Stability AI, then Jasper), which may create uncertainty about long-term standalone product direction.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Free tier is limited in volume and adds a watermark to output.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Advanced/business use requires either the Pro subscription or a separate metered API relationship via Jasper.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Who owns Clipdrop now?$q$, $q$Clipdrop is currently owned by Jasper, which acquired it from Stability AI on February 20, 2024. Stability AI had itself acquired Clipdrop (via its maker, Init ML) in March 2023.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Is Clipdrop free?$q$, $q$Clipdrop has a free tier with a limited number of processed images per month and a watermark; a Pro plan at $9/month removes the watermark and unlocks HD, unlimited-style usage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$What is Clipdrop's Relight feature?$q$, $q$Relight lets users add, move, and adjust virtual light sources on an already-taken portrait or product photo, a feature not commonly found in competing tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Can developers use Clipdrop via an API?$q$, $q$Yes, Clipdrop offers a metered developer API with per-call pricing for features like background removal and Stable Diffusion XL image generation, with tiered rate limits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Who founded Clipdrop?$q$, $q$Clipdrop was founded in 2020 by Google alumni Cyril Diagne, Damien Henry, and Jonathan Blanchet under the company Init ML, based in Paris, France.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$E-commerce product photo editing$q$, $q$Sellers use Clipdrop's background removal and relighting to produce clean, consistent product photos.$q$, $q$E-commerce sellers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Quick marketing image edits$q$, $q$Marketers use Clipdrop for fast object removal, upscaling, and background changes without a full design tool.$q$, $q$Marketing teams and content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Embedded image processing$q$, $q$Developers use the Clipdrop API to add background removal or AI image generation into their own applications.$q$, $q$Developers and software teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Limited monthly image processing","Watermarked output"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$Pro$q$, $q$$9/month$q$, $q$monthly$q$, NULL, $q$["No watermark","HD resolution output","Higher usage limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$API (metered)$q$, $q$From ~$0.002/call$q$, $q$usage-based$q$, NULL, $q$["Background removal API","SDXL image generation API","Tiered rate limits (Free/Pro/Enterprise)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clipdrop is an AI-powered photo and image editing toolkit founded in 2020 in Paris, France by Cyril Diagne, Damien Henry, and Jonathan Blanchet under the company Init ML. Stability AI acquired Clipdrop in March 2023, and Jasper subsequently acquired it from Stability AI in February 2024.$q$, $q$Individual users can still buy Clipdrop as a standalone product at clipdrop.co, while business customers can access its capabilities through the Jasper API as part of Jasper's broader AI marketing platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clipdrop's toolkit includes Remove Background, Cleanup (object removal), Relight (adjustable virtual lighting on portraits/products), Uncrop (generative aspect-ratio expansion), Reimagine (photo variation generation), an image Upscaler, Replace Background, and Stable Doodle (sketch-to-image), plus direct Stable Diffusion XL text-to-image generation.$q$, $q$Relight is frequently cited as Clipdrop's standout differentiator, allowing users to add, move, and adjust light sources on an existing photo after it was taken.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clipdrop offers a free tier with a limited number of processed images per month and a watermark, and a Pro plan at $9/month that removes the watermark, unlocks HD output, and lifts usage limits.$q$, $q$Developers can access Clipdrop via a metered API, with per-call pricing (roughly $0.002 for background removal, $0.005 for SDXL generation) and tiered rate limits across Free, Pro, and Enterprise API keys.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ee6e97e-879a-408e-b289-62614630623b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Timers & manual entry$q$, $q$Start/stop timers or log time manually, with an auto-tracker that detects time spent in apps and websites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Timesheets & approvals$q$, $q$Weekly timesheets with locking and manager approval workflows on Standard tier and above.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Reporting$q$, $q$Detailed reports by project, client, or team member, exportable as PDF, CSV, or Excel, or shareable via live link.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Invoicing$q$, $q$Generate invoices directly from tracked time and expenses, with recurring invoice support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Budgeting & forecasting$q$, $q$Project budgets, cost estimates, and labor cost/profit analysis available on the Pro tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$GPS tracking & screenshots$q$, $q$Location tracking and periodic screenshots for field or remote workforce monitoring on Pro tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$90+ integrations$q$, $q$Connects with popular project management and communication tools to embed time tracking into existing workflows.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free plan available for small teams (up to 5 users) with core tracking functionality.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Wide integration library (90+ apps) for embedding time tracking into existing tools.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Granular paid tiers let teams pay only for the billing, approval, or security features they need.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Bundled pricing with Pumble and Plaky offers savings for teams wanting a full productivity suite.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free plan was reduced from unlimited users to a 5-user cap as of April 2026.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Invoicing, GPS tracking, and advanced reporting are locked behind mid-to-upper paid tiers.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Enterprise security features (SSO, SCIM, audit logs) require the top-priced plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Is Clockify free?$q$, $q$Clockify has a free plan, but as of April 2026 it is capped at 5 users. Larger teams need a paid plan starting at $3.99/user/month (annual billing).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Does Clockify support invoicing?$q$, $q$Yes, invoicing and recurring invoices are available starting on the Standard plan ($5.49/user/month annual).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Who owns Clockify?$q$, $q$Clockify is made by CAKE.com Inc. (formerly COING), headquartered in Palo Alto, California, which also owns Pumble and Plaky.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Does Clockify have GPS tracking?$q$, $q$Yes, GPS tracking is available on the Pro plan ($7.99/user/month annual) along with screenshots and expense tracking.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$How many integrations does Clockify support?$q$, $q$Clockify supports more than 90 third-party integrations across project management and communication tools.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Freelance and small-team time tracking$q$, $q$Freelancers and small teams (up to 5 users) use the free plan for basic timers, timesheets, and reporting.$q$, $q$Freelancers and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Agency billing and invoicing$q$, $q$Agencies use Standard-tier invoicing and approvals to bill clients directly from tracked time.$q$, $q$Agencies and consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Enterprise workforce time management$q$, $q$Larger organizations use Pro/Enterprise tiers for budgeting, forecasting, GPS tracking, and SSO/audit compliance.$q$, $q$Enterprise operations and HR teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 5 users","Unlimited time tracking","Timesheets","Basic reporting","Mobile/desktop apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Basic$q$, $q$$3.99/user/month$q$, $q$annual ($4.99 monthly)$q$, NULL, $q$["Kiosk mode","Add time for others","Bulk edit","Break tracking","Time estimates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Standard$q$, $q$$5.49/user/month$q$, $q$annual ($6.99 monthly)$q$, NULL, $q$["Invoicing","Timesheet approval & locking","Time off tracking","Manager role","QuickBooks integration"]$q$::jsonb, 2);
