INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Enterprise$q$, $q$$11.99/user/month$q$, $q$annual ($14.99 monthly)$q$, NULL, $q$["Single sign-on (SSO)","Custom subdomain","SCIM provisioning","Audit log"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clockify is a time-tracking and timesheet platform launched in 2017 by CAKE.com Inc. (formerly COING), headquartered in Palo Alto, California. It is the flagship product in the CAKE.com productivity suite, alongside team chat app Pumble and project management app Plaky.$q$, $q$Clockify built its reputation on offering time tracking to a large number of users for free; as of April 2026 the free tier is capped at 5 users, with unlimited-user access now reserved for paid plans.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include timers and manual time entry, timesheets, an auto-tracker for detecting app/website usage, calendar views, and reporting exportable as PDF, CSV, or Excel. Paid tiers layer on invoicing, timesheet approvals, budgeting/forecasting, GPS tracking, and screenshots.$q$, $q$Clockify integrates with 90+ third-party apps for project management and communication, and supports multi-currency billing and QuickBooks integration on Standard tier and above.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clockify's Free plan (capped at 5 users as of April 2026) includes core tracking and basic reporting. Paid plans are Basic ($3.99/user/month annual), Standard ($5.49), Pro ($7.99), and Enterprise ($11.99), each unlocking progressively more advanced billing, approval, and security features.$q$, $q$A CAKE.com bundle combines Enterprise-tier Clockify with Pumble and Plaky at $12.99/user/month (annual), pitched as a roughly 53% savings versus buying the three products separately.$q$]::text[], 2);
